// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const configGet = await fetch(`/platform/automation/v1/executions/${execution_id}/tasks/get-status/result`);
  const configBody = await configGet.json();
  const status = configBody.AutomationExecution.AutomationExecutionStatus.toUpperCase()
  console.log(status)

  if (status =="INPROGRESS" || status =="PENDING" ) {
        console.log("Automation still running, restarting again!");
        throw new Error("Automation still running, restarting again!");
  } 

  return configBody;
}
